interface.signature:
PUT /api/courses/{slug}/lessons/{id}
Request Body: { lesson: UpdateLessonData }
UpdateLessonData: {
  title?: string | null;
  core_practice?: string | null;
  key_point?: string | null;
  tone?: string | null;
  duration_minutes?: number | null;
  status?: string | null;
  script?: Record<string, never> | null;
  audio_url?: string | null;
}
Response: LessonResponse (200 OK) or HTTPValidationError (422)

interface ScriptPart {
  type: 'speak' | 'pause';
  content?: string | null; // For speak parts
  duration?: number | null; // For pause parts (seconds)
}

interface Lesson {
  id: number;
  title: string;
  status: LessonStatus;
  script?: ScriptPart[] | null;
  durationMinutes: number;
  updatedAt: string;
  scriptGeneratedAt?: string | null;
  // ... other fields
}

function calculateScriptMetrics(
  script: Array<{ type: string; content?: string | null; duration?: number | null }>,
  targetDurationMinutes: number
): ScriptMetrics
// Returns: { wordCount, charCount, readingTimeMinutes, totalPauseSeconds, totalDurationMinutes, pausePercentage, targetDurationMinutes }
